data.query:
mutation giftCardUpdate($id: ID!, $input: GiftCardUpdateInput!) {
    giftCardUpdate(id: $id, input: $input) {
        giftCard {
            id
            balance {
                amount
                currencyCode
            }
            createdAt
            customer {
                id
            }
            deactivatedAt
            enabled
            expiresOn
            initialValue {
                amount
                currencyCode
            }
            lastCharacters
            maskedCode
            note
            templateSuffix
            updatedAt
        }
        userErrors {
            field
            message
        }
    }
}
